sys_script_include.script:
var TableRowActionsSanitizer = Class.create();
TableRowActionsSanitizer.prototype = {
    sanitizeHref: function (rawHref) {
        if (!rawHref) {
            return "";
        }

        var href = String(rawHref).trim();
        if (!href) {
            return "";
        }

        // Block explicitly unsafe schemes
        if (/^(javascript:|data:|vbscript:)/i.test(href)) {
            return "";
        }

        // Allow safe in-portal and relative routes
        if (
            href.indexOf("?") === 0 ||
            href.indexOf("/") === 0 ||
            href.indexOf("#") === 0
        ) {
            return href;
        }

        // Allow explicit safe schemes only
        if (/^(https?:|mailto:|tel:)/i.test(href)) {
            return href;
        }

        // Allow remaining non-schemed relative URLs like "id=contacts"
        if (!/^[a-zA-Z][a-zA-Z\d+.-]*:/.test(href)) {
            return href;
        }

        return "";
    },

    sanitizeTarget: function (rawTarget) {
        var target = String(rawTarget || "_self").trim();
        var allowedTargets = {
            _self: true,
            _blank: true,
            _parent: true,
            _top: true,
        };

        return allowedTargets[target] ? target : "_self";
    },

    type: "TableRowActionsSanitizer",
};
